            package main

import (
	"io"
	"net/http"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
	"golang.org/x/net/html"
)

// PreviewRequest represents the expected JSON payload.
type PreviewRequest struct {
	URL string `json:"url"`
}

// PreviewResponse represents the JSON response containing the parsed data.
type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

// FetchURLPreview handles POST requests to fetch and parse a URL's title and meta description.
func FetchURLPreview(ctx echo.Context) error {
	var req PreviewRequest

	// Bind JSON body
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "invalid request body"})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "url field is required"})
	}

	// Initialize HTTP client with a strict 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Create request with context
	httpReq, err := http.NewRequestWithContext(ctx.Request().Context(), http.MethodGet, req.URL, nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to create request"})
	}

	// Set a standard User-Agent to prevent being blocked by some web servers
	httpReq.Header.Set("User-Agent", "Go-URL-Preview-Fetcher/1.0")

	// Execute the request
	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusGatewayTimeout, map[string]string{"error": "failed to fetch url or timed out"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "url returned non-200 status code"})
	}

	var title, description string
	var inTitle bool

	// Limit reading to 1MB to prevent memory exhaustion from unusually large pages
	bodyReader := io.LimitReader(resp.Body, 1024*1024)
	z := html.NewTokenizer(bodyReader)

parseLoop:
	for {
		tt := z.Next()
		if tt == html.ErrorToken {
			break parseLoop
		}

		switch tt {
		case html.StartTagToken, html.SelfClosingTagToken:
			t := z.Token()
			if t.Data == "title" {
				inTitle = true
			} else if t.Data == "meta" {
				var isDesc bool
				var content string
				for _, a := range t.Attr {
					if a.Key == "name" && strings.EqualFold(a.Val, "description") {
						isDesc = true
					} else if a.Key == "content" {
						content = a.Val
					}
				}
				// Assign the first meta description found
				if isDesc && description == "" {
					description = content
				}
			}
		case html.TextToken:
			if inTitle {
				title += z.Token().Data
			}
		case html.EndTagToken:
			t := z.Token()
			if t.Data == "title" {
				inTitle = false
			} else if t.Data == "head" {
				// We can stop parsing safely once the head section is closed
				break parseLoop
			}
		}
	}

	// Return extracted data
	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       strings.TrimSpace(title),
		Description: strings.TrimSpace(description),
	})
}

func main() {
	e := echo.New()

	// Register the handler under the /preview path
	e.POST("/preview", FetchURLPreview)

	// Start the server
	e.Logger.Fatal(e.Start(":8080"))
}

