// FetchURLPreview handles POST requests to fetch and parse URL previews
func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid request body"})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL field is required"})
	}

	// Create an HTTP client with a 3-second timeout requirement
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Create a new HTTP request using the context from Echo
	httpReq, err := http.NewRequestWithContext(ctx.Request().Context(), http.MethodGet, req.URL, nil)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}

