	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	// Execute the request
	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch the provided URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "Received non-200 status code from the URL"})
	}

	// Parse the HTML body to extract the title and description
	title, description := parseHTMLForPreview(resp.Body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// parseHTMLForPreview tokenizes the HTML stream and extracts the title and meta description
func parseHTMLForPreview(r io.Reader) (string, string) {
	z := html.NewTokenizer(r)
	var title, description string

	for {
		tt := z.Next()
		if tt == html.ErrorToken {
			break // End of document or error
		}

		t := z.Token()

		switch tt {
		case html.StartTagToken:
			if t.Data == "title" {
				var titleBuilder strings.Builder
				// Accumulate text tokens until the closing </title> tag
				for {
					nextTt := z.Next()
					if nextTt == html.TextToken {
						titleBuilder.WriteString(z.Token().Data)
					} else if nextTt == html.EndTagToken && z.Token().Data == "title" {
						break
					} else if nextTt == html.ErrorToken {
						break
					}
				}
				title = titleBuilder.String()
			} else if t.Data == "meta" {
				description = extractDescriptionFromMeta(t, description)
			}
		case html.SelfClosingTagToken:
			if t.Data == "meta" {
				description = extractDescriptionFromMeta(t, description)
			}
		}

		// Early exit if both fields are found
		if title != "" && description != "" {
			break
		}
	}

	return strings.TrimSpace(title), strings.TrimSpace(description)
