	for _, attr := range t.Attr {
		if attr.Key == "name" {
			name = strings.ToLower(attr.Val)
		} else if attr.Key == "content" {
			content = attr.Val
		}
	}

	if name == "description" {
		return content
	}

	return currentDesc
}

func main() {
	// Initialize Echo instance
	e := echo.New()

	// Middleware
	e.Use(middleware.Logger())
	e.Use(middleware.Recover())

	// Register the FetchURLPreview handler under the /preview path
	e.POST("/preview", FetchURLPreview)

	// Start the server
	e.Logger.Fatal(e.Start(":8080"))
