	}

	var title, description string

	// traverse is a recursive function to walk through the HTML nodes
	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		// Extract Title
		if n.Type == html.ElementNode && n.Data == "title" && title == "" {
