func extractText(n *html.Node) string {
	if n.Type == html.TextNode {
		return n.Data
	}
	var result string
	for c := n.FirstChild; c != nil; c = c.NextSibling {
		result += extractText(c)
	}
	return result
}

// FetchURLPreview handles the POST request to fetch and parse URL previews.
func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid request body"})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL field is required"})
	}

	// Create an HTTP client with a 3-second timeout as required.
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Fetch the provided URL.
	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "Received non-200 response from the URL"})
	}

	// Limit reading to 1MB to prevent large memory allocation on huge pages.
	limitedBody := io.LimitReader(resp.Body, 1024*1024)

	// Parse the HTML content.
	doc, err := html.Parse(limitedBody)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to parse HTML content"})
	}

	var title, description string

	// traverse recursively searches the parsed HTML nodes for title and meta description.
	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			if n.Data == "title" && title == "" {
				title = extractText(n)
			} else if n.Data == "meta" {
				var isDesc bool
				var content string
				for _, attr := range n.Attr {
					if attr.Key == "name" && strings.ToLower(attr.Val) == "description" {
						isDesc = true
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if isDesc && description == "" {
					description = content
				}
			}
		}

		// Continue traversing the tree
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			// Optimization: stop traversing if both fields are already found
			if title != "" && description != "" {
				return
			}
			traverse(c)
		}
	}

	traverse(doc)

	// Return the extracted metadata as JSON.
	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       strings.TrimSpace(title),
		Description: strings.TrimSpace(description),
	})
}

func main() {
	e := echo.New()

	// Register the handler under the /preview path
	e.POST("/preview", FetchURLPreview)

	// Start the server
	e.Logger.Fatal(e.Start(":8080"))
