	// Limit to 1MB to avoid Out-Of-Memory issues on large files
	body, err := io.ReadAll(io.LimitReader(resp.Body, 1024*1024))
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	title, description := extractTitleAndDescription(body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func extractTitleAndDescription(htmlContent []byte) (string, string) {
	htmlStr := string(htmlContent)

	var title, description string

	// Extract Title
	titleRe := regexp.MustCompile(`(?is)<title[^>]*>(.*?)</title>`)
	titleMatch := titleRe.FindStringSubmatch(htmlStr)
	if len(titleMatch) > 1 {
		title = strings.TrimSpace(titleMatch[1])
	}

	// Extract Description
	metaRe := regexp.MustCompile(`(?is)<meta\s+([^>]+)>`)
	metaMatches := metaRe.FindAllStringSubmatch(htmlStr, -1)

	nameRe := regexp.MustCompile(`(?i)name\s*=\s*["']?description["']?`)
	contentRe := regexp.MustCompile(`(?i)content\s*=\s*(?:["']([^"']+)["']|([^\s>]+))`)

	for _, match := range metaMatches {
		if len(match) > 1 {
			attrs := match[1]
			if nameRe.MatchString(attrs) {
				contentMatch := contentRe.FindStringSubmatch(attrs)
				if len(contentMatch) > 1 {
					if contentMatch[1] != "" {
						description = strings.TrimSpace(contentMatch[1])
					} else if len(contentMatch) > 2 && contentMatch[2] != "" {
						description = strings.TrimSpace(contentMatch[2])
					}
					break
				}
			}
		}
	}

	return title, description
}

