// FetchURLPreview handles the POST request to fetch and parse a URL.
func FetchURLPreview(ctx echo.Context) error {
	var req PreviewRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "invalid JSON body"})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "url field is required"})
	}

	// Set the timeout to 3 seconds as required
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to fetch URL: " + err.Error()})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "received non-200 response from the provided URL"})
	}

	// Parse the HTML content to extract the title and meta description
	title, description := parseHTML(resp.Body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       strings.TrimSpace(title),
		Description: strings.TrimSpace(description),
	})
}

// parseHTML reads the HTML body and extracts the title and meta description.
func parseHTML(r io.Reader) (string, string) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", ""
	}

	var title, description string
	var traverse func(*html.Node)

	traverse = func(n *html.Node) {
		// Extract Title
		if n.Type == html.ElementNode && n.Data == "title" {
			if title == "" {
				title = extractText(n)
			}
		}

		// Extract Meta Description
		if n.Type == html.ElementNode && n.Data == "meta" {
			var isDescription bool
			var content string
			for _, attr := range n.Attr {
				if attr.Key == "name" && strings.ToLower(attr.Val) == "description" {
					isDescription = true
				}
				if attr.Key == "content" {
					content = attr.Val
				}
			}
			if isDescription && description == "" {
				description = content
			}
		}

		// Continue traversing the tree
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return title, description
}

// extractText recursively extracts text content from an HTML node.
func extractText(n *html.Node) string {
	if n.Type == html.TextNode {
		return n.Data
	}
	var result string
	for c := n.FirstChild; c != nil; c = c.NextSibling {
		result += extractText(c)
	}
	return result
}

