	// Create an HTTP client with a 3-second timeout requirement
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Fetch the URL content
	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL: " + err.Error()})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "Target URL returned non-200 status code"})
	}

	// Limit the reader to 1MB to prevent memory exhaustion from maliciously large pages
	limitReader := io.LimitReader(resp.Body, 1024*1024)

	var title, description string
	var inTitle bool

	// Parse the HTML document
	z := html.NewTokenizer(limitReader)
	for {
		tt := z.Next()
		if tt == html.ErrorToken {
			break // End of document or error (including EOF)
		}

		t := z.Token()

		switch tt {
		case html.StartTagToken, html.SelfClosingTagToken:
			if t.Data == "title" {
				inTitle = true
			} else if t.Data == "meta" {
				var name, content string
				for _, attr := range t.Attr {
					if strings.EqualFold(attr.Key, "name") || strings.EqualFold(attr.Key, "property") {
						name = attr.Val
					} else if strings.EqualFold(attr.Key, "content") {
						content = attr.Val
					}
				}
				// Support both standard description and OpenGraph description
				if strings.EqualFold(name, "description") || strings.EqualFold(name, "og:description") {
					if description == "" { // Keep the first description found
						description = content
					}
				}
			}
		case html.EndTagToken:
			if t.Data == "title" {
				inTitle = false
			}
		case html.TextToken:
			if inTitle {
				title += t.Data
			}
		}
	}

	// Clean up extracted texts
	title = strings.TrimSpace(title)
	description = strings.TrimSpace(description)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

