// extractHTMLMetadata parses the HTML body and returns the page title and meta description.
func extractHTMLMetadata(body io.Reader) (string, string) {
	tokenizer := html.NewTokenizer(body)
	var title, description string
	inTitle := false

	for {
		tt := tokenizer.Next()
		if tt == html.ErrorToken {
			break
		}

