// extractText recursively extracts text content from an HTML node.
func extractText(n *html.Node) string {
	if n.Type == html.TextNode {
		return n.Data
	}
	var result string
	for c := n.FirstChild; c != nil; c = c.NextSibling {
		result += extractText(c)
	}
	return result
}

// FetchURLPreview handles POST requests to fetch and parse URL metadata.
func FetchURLPreview(ctx echo.Context) error {
	var req PreviewRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, PreviewResponse{Error: "Invalid request body"})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, PreviewResponse{Error: "URL is required"})
	}

	// Set the timeout to exactly 3 seconds as required.
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, PreviewResponse{Error: "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, PreviewResponse{Error: "Received non-200 response from URL"})
	}

	// Limit reading to 1MB to prevent memory exhaustion on large pages
	limitReader := io.LimitReader(resp.Body, 1024*1024)
	doc, err := html.Parse(limitReader)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, PreviewResponse{Error: "Failed to parse HTML"})
	}

	var title, description string

	// Traverse the HTML AST to find the <title> and <meta name="description">
	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode && n.Data == "title" {
			if title == "" {
				title = extractText(n)
			}
		}

		if n.Type == html.ElementNode && n.Data == "meta" {
			var name, content string
			for _, a := range n.Attr {
				if strings.EqualFold(a.Key, "name") || strings.EqualFold(a.Key, "property") {
					name = a.Val
				}
				if strings.EqualFold(a.Key, "content") {
