	}

	// Requirement: Set the timeout to 3 seconds when fetching the provided URL
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch the provided URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "Target URL returned a non-200 status code"})
	}

	// Use a LimitReader to prevent memory exhaustion from excessively large responses (limit to 1MB)
	limitReader := io.LimitReader(resp.Body, 1024*1024)

	title, description := extractHTMLMetadata(limitReader)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// extractHTMLMetadata parses the HTML stream and extracts the title and meta description
func extractHTMLMetadata(r io.Reader) (string, string) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", ""
	}

	var title, description string

	var f func(*html.Node)
	f = func(n *html.Node) {
		// Stop traversing if we have already found both targets
		if title != "" && description != "" {
			return
		}

		if n.Type == html.ElementNode {
			// Extract <title> tag text
			if n.Data == "title" && title == "" {
				var t strings.Builder
				for c := n.FirstChild; c != nil; c = c.NextSibling {
					if c.Type == html.TextNode {
						t.WriteString(c.Data)
					}
				}
				title = strings.TrimSpace(t.String())
			}

			// Extract <meta name="description" content="...">
			if n.Data == "meta" && description == "" {
