	Description string `json:"description"`
}

// FetchURLPreview handles the POST /preview request.
func FetchURLPreview(ctx echo.Context) error {
	var req PreviewRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON payload"})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL field is required"})
	}

	// Set a 3-second timeout for the HTTP client as required.
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Create a new request using the context from echo.
	httpReq, err := http.NewRequestWithContext(ctx.Request().Context(), http.MethodGet, req.URL, nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to create request"})
	}

	// Fetch the URL content.
	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "Received non-200 response from the provided URL"})
	}

	// Parse the HTML document.
	doc, err := html.Parse(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to parse HTML content"})
	}

	var title, description string

	// traverse recursively searches the HTML nodes for the title and meta description.
	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		// Extract <title>
		if n.Type == html.ElementNode && n.Data == "title" && title == "" {
			var textContent string
			for c := n.FirstChild; c != nil; c = c.NextSibling {
				if c.Type == html.TextNode {
					textContent += c.Data
				}
			}
			title = strings.TrimSpace(textContent)
		}

		// Extract <meta name="description" content="...">
		if n.Type == html.ElementNode && n.Data == "meta" {
			var isDescription bool
			var content string
			for _, attr := range n.Attr {
				if attr.Key == "name" && strings.EqualFold(attr.Val, "description") {
					isDescription = true
				}
				if attr.Key == "content" {
					content = attr.Val
				}
			}
			if isDescription && description == "" {
				description = strings.TrimSpace(content)
			}
		}

		// Continue traversing children
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)

	// Return the extracted information as JSON.
	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func main() {
	// Initialize echo instance
	e := echo.New()

	// Register the handler under the /preview path
	e.POST("/preview", FetchURLPreview)

	// Start the server
	e.Logger.Fatal(e.Start(":8080"))
}

