		Title:       strings.TrimSpace(title),
		Description: strings.TrimSpace(description),
	})
}

// extractMetadata parses HTML and extracts the page title and meta description.
func extractMetadata(r io.Reader) (string, string) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", ""
	}

	var title, description string
	var traverse func(*html.Node)

	traverse = func(n *html.Node) {
		// Extract <title>
		if n.Type == html.ElementNode && n.Data == "title" {
			if n.FirstChild != nil && title == "" {
				title = n.FirstChild.Data
			}
		}

		// Extract <meta name="description" content="...">
		if n.Type == html.ElementNode && n.Data == "meta" {
			var isDescription bool
			var content string
			for _, attr := range n.Attr {
				if attr.Key == "name" && strings.EqualFold(attr.Val, "description") {
					isDescription = true
				}
				if attr.Key == "content" {
					content = attr.Val
				}
			}
			if isDescription && description == "" {
				description = content
			}
		}

		// Stop traversing if we already found both to save time
		if title != "" && description != "" {
			return
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return title, description
}

func main() {
	// Initialize Echo instance
	e := echo.New()

	// Register the handler
	e.POST("/preview", FetchURLPreview)

	// Start the server
	e.Logger.Fatal(e.Start(":8080"))
}

